    id character varying DEFAULT gen_random_uuid() NOT NULL,
    workplace_id character varying NOT NULL,
    worker_user_id character varying NOT NULL,
    status text DEFAULT 'active'::text NOT NULL,
    invited_by_user_id character varying,
    invited_at timestamp without time zone DEFAULT now() NOT NULL,
    accepted_at timestamp without time zone,
    notes text,
    created_at timestamp without time zone DEFAULT now() NOT NULL,
    updated_at timestamp without time zone DEFAULT now() NOT NULL
);


ALTER TABLE public.workplace_assignments OWNER TO postgres;

--
-- Name: workplaces; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE public.workplaces (
    id character varying DEFAULT gen_random_uuid() NOT NULL,
    name text NOT NULL,
    address_line1 text,
    city text,
    province text,
    postal_code text,
    country text DEFAULT 'Canada'::text,
    latitude double precision,
    longitude double precision,
    geofence_radius_meters integer DEFAULT 150,
    is_active boolean DEFAULT true,
    created_at timestamp without time zone DEFAULT now() NOT NULL,
    updated_at timestamp without time zone DEFAULT now() NOT NULL,
    crm_external_id text,
    crm_source boolean DEFAULT false
);


ALTER TABLE public.workplaces OWNER TO postgres;

